import{_ as e,o as n,c as a,a2 as o}from"./chunks/framework.m9rfQn3T.js";const c=JSON.parse('{"title":"AI-Agent开发要学什么","description":"","frontmatter":{"title":"AI-Agent开发要学什么","date":"2026-06-08T22:43:56.000Z","permalink":"/pages/a5863a7e31fc/","categories":["笔记","Agent学习笔记"],"tags":[null]},"headers":[],"relativePath":"09.AI/100.Agent学习笔记/01.AI-Agent开发要学什么.md","filePath":"09.AI/100.Agent学习笔记/01.AI-Agent开发要学什么.md","lastUpdated":1782538095000}'),r={name:"09.AI/100.Agent学习笔记/01.AI-Agent开发要学什么.md"};function g(s,t,l,i,A,_){return n(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="ai-agent-开发要学什么" tabindex="-1">AI Agent 开发要学什么 <a class="header-anchor" href="#ai-agent-开发要学什么" aria-label="Permalink to &quot;AI Agent 开发要学什么&quot;">​</a></h1><p>大模型很强，但它有几个硬伤：</p><ul><li><strong>没记忆</strong> — 昨天聊的今天全忘了</li><li><strong>没手</strong> — 只能告诉你怎么做，不能帮你做</li><li><strong>没私有知识</strong> — 公司内部文档它一概不知</li><li><strong>没时事</strong> — 训练数据截止之后的事它不知道</li></ul><p>所以 Agent 要做的，就是给大模型打补丁：</p><ul><li><strong>Memory</strong> — 让它记住该记的，忘记该忘的</li><li><strong>Tool</strong> — 让它能读写文件、跑命令、开浏览器，真正动手</li><li><strong>RAG</strong> — 接入私有知识库，查到它本来不知道的东西</li></ul><p>大模型本身就具备思考和规划能力，加上这三样，就是一个能记住你、能帮你干活、能查内部知识的 Agent。</p><p>平时用的 Cursor、Manus，本质上都是这个思路 — 用 Tool 把能力扩展到模型之外。</p><p>接下来要学的东西：RAG、Memory、Tool、MCP、Multi Agent，以及开发框架 <strong>LangChain</strong>（Agent 框架）和 <strong>LangGraph</strong>（多 Agent 框架）。</p>',8)])])}const d=e(r,[["render",g]]);export{c as __pageData,d as default};
